# OEIS sequence: A332533

def A332533(n):
    if n == 1: return 1
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k*n**(j-1)*(n**(m-j+1)-1)
        j = m+1
    return c//(n-1) # _Chai Wah Wu_, May 11 2026

